如果日期格式固定，我会用 re.sub 匹配日期模式。代码：
import re

def replace_date(text, new_date):
    return re.sub(r'\d{4}-\d{2}-\d{2}', new_date, text)

assert replace_date('created_at=2026-06-28', '2026-07-01') == 'created_at=2026-07-01'
assert replace_date('no date', '2026-07-01') == 'no date'

我会用字典或 Counter。手写版本能展示基础能力。代码：
def count_chars(text):
    result = {}
    for char in text:
        result[char] = result.get(char, 0) + 1
    return result

assert count_chars('aba') == {'a': 2, 'b': 1}
assert count_chars('') == {}

我会复制第一个字典，再遍历第二个字典累加。代码：
def merge_sum(left, right):
    result = dict(left)
    for key, value in right.items():
        result[key] = result.get(key, 0) + value
    return result

assert merge_sum({'a': 1, 'b': 2}, {'a': 3, 'c': 4}) == {'a': 4, 'b': 2, 'c': 4}
assert merge_sum({}, {'x': 1}) == {'x': 1}

我会按行拆分，判断每行是否包含 ERROR。代码：
def count_error_lines(log_text):
    return sum(1 for line in log_text.splitlines() if 'ERROR' in line)

log = 'INFO start\nERROR failed\nWARN retry\nERROR done'
assert count_error_lines(log) == 2
assert count_error_lines('INFO ok') == 0

我会用 datetime.strptime，捕获 ValueError。这样 2026-02-30 这种格式正确但日期非法的值也能识别。代码：
from datetime import datetime

def is_valid_date(text):
    try:
        datetime.strptime(text, '%Y-%m-%d')
        return True
    except ValueError:
        return False

assert is_valid_date('2026-06-28') is True
assert is_valid_date('2026-02-30') is False

如果不要求保留重复，我会用 set。代码：
def intersection_and_diff(left, right):
    left_set = set(left)
    right_set = set(right)
    return left_set & right_set, left_set - right_set

same, only_left = intersection_and_diff([1, 2, 3], [2, 3, 4])
assert same == {2, 3}
assert only_left == {1}

我会用 sorted 的 key 参数。代码：
def sort_by_field(items, field):
    return sorted(items, key=lambda item: item[field])

data = [{'name': 'b', 'age': 30}, {'name': 'a', 'age': 20}]
assert sort_by_field(data, 'age') == [{'name': 'a', 'age': 20}, {'name': 'b', 'age': 30}]
